def mod_inverse_fermat(a, m):
    if m <= 1:
        raise ValueError("Modulus 'm' must be a prime number greater than 1 for Fermat's Little Theorem.")
    if a % m == 0:
        raise ValueError("Cannot find inverse: 'a' is a multiple of 'm'.")

    a = a % m

    inverse = pow(a, m - 2, m)
    return inverse
